/**/
/* Botón CONTINUAR con ícono FontAwesome al final */

[selector="submit-boton"]{
  text-align: right;
  margin-top: 12px;
}


[selector="submit-boton"] button.btn-success {
  position: relative;
  padding-right: 35px; /* espacio para ícono */
  transition: background-color 0.3s ease, color 0.3s ease;
}

/* Pseudo-elemento con ícono */
[selector="submit-boton"] button.btn-success::after {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  content: "\f1d8"; /* paper-plane */
  position: absolute;
  top: 50%;
  right: 0.75rem;
  transform: translateY(-50%);
  font-size: 1rem;
  color: #fff;
  pointer-events: none;
}

/* Opcional: efecto al pasar el mouse */
[selector="submit-boton"] button.btn-success:hover::after {
  transform: translateY(-50%) scale(1.1);
}


[selector="submit-boton-false"]{
