/*
Estilos basicos Zurich Regional
*/
.form-group {
  margin-bottom: 16px;
}

.form-nested-screen{
  padding: 14px 18px;
}

.required-asterisk {
  display: inline;
}

label {
  display: inline;
}

form > .form-check {
  display: inline-flex;           
  margin-right: 16px;           
  margin-bottom: 4px;              
}

.form-check-label{
  margin-top: 16px;
}

.form-check{
  margin-bottom: -8px;
}


input,
textarea {
  display: block;
  border-radius: 6px;
  height: 41px;
}

.form-group.has-errors .multiselect {
  margin-bottom: -12px;
}

.multiselect .multiselect__tags {
