}

/*CSS DE MODAL */
/* Contenedor general del modal */
[selector="contenido-modal-preventivo"]{
  padding: 22px 18px 0px;
  margin: -25px 0px -19px 0px;
  font-family: "Segoe UI", Roboto, sans-serif;
  background-color: #ffffff;
  color: #2c2c2c;
}

/* Ícono decorativo generado por CSS */
[selector="contenido-modal-preventivo"] .icono-alerta::before {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  content: "\f06a"; /* fa-exclamation-circle */
  font-size: 2.8rem;
  color: #2167AE; /* Azul Zurich */
  display: inline-block;
  margin-bottom: -6px;
}

/* Título */
[selector="contenido-modal-preventivo"] .titulo-modal {
  font-size: 1.3rem;
  font-weight: 600;
  color: #2167AE;
}

/* Texto del cuerpo */
[selector="contenido-modal-preventivo"] .texto-modal {
  font-size: 1.05rem;
  line-height: 1.6;
  color: #333333;
}

[selector="contenido-modal-preventivo"] .texto-modal-sub {
  font-size: 14px;
  padding-top: 5px;
}



/* Sombra y estilo del modal */
.modal-content {
  border-radius: 12px;
  box-shadow: 0 0 18px rgba(0, 0, 0, 0.12);
  border: 1px solid #dfe6ec;
}

.modal-footer{
  padding: 10px 15px 8px !important;
}
